import {Injectable} from '@angular/core';
import {HttpClient} from '@angular/common/http';
import {Observable} from 'rxjs';
import {Regions} from '../dto/regions';
import {API_REGIONS} from '../../../../environments/url';

@Injectable({
  providedIn: 'root'
})
export class RegionsApiService {

  constructor(
    private httpClient: HttpClient
  ) {
  }

  regions(): Observable<Regions[]> {
    return this.httpClient.get<Regions[]>(API_REGIONS);
  }
}
