import {Component, OnInit} from '@angular/core';
import {FormControl, FormGroup, Validators} from '@angular/forms';
import {NgxSmartModalService} from 'ngx-smart-modal';
import {Observable} from 'rxjs';
import {News} from '../../shared/api/dto/news';
import {Pageable} from '../../shared/api/dto/pageable';
import {NewsApiService} from '../../shared/api/news/news-api.service';
import {Categories} from '../../shared/api/dto/categories';
import {Regions} from '../../shared/api/dto/regions';
import {RegionsApiService} from '../../shared/api/regions/regions-api.service';
import {CategoriesApiService} from '../../shared/api/categories/categories-api.service';

@Component({
  selector: 'app-news-list',
  templateUrl: './news-list.component.html',
  styleUrls: ['./news-list.component.sass']
})
export class NewsListComponent implements OnInit {
  form: FormGroup;
  isOnSearch = false;
  news$: Observable<Pageable<News>>;
  newsOffset = 0;
  newsLimit = 20;
  categories$: Observable<Categories[]>;
  regions$: Observable<Regions[]>;

  constructor(
    private ngxSmartModalService: NgxSmartModalService,
    private newsApiService: NewsApiService,
    private regionsApiService: RegionsApiService,
    private categoriesApiService: CategoriesApiService
  ) {
  }

  ngOnInit(): void {
    this.initForm();
    this.initNews();
    this.initRegions();
    this.initCategories();
  }

  initNews(): void {
    this.news$ = this.newsApiService.news(this.newsOffset, this.newsLimit);
  }

  initRegions(): void {
    this.regions$ = this.regionsApiService.regions();
  }

  initCategories(): void {
    this.categories$ = this.categoriesApiService.categories();
  }

  initForm(): void {
    this.form = new FormGroup({
      search: new FormControl(
        '',
        Validators.required
      )
    });
  }

  onSearch(): void {
    this.isOnSearch = true;
  }

  offSearch(): void {
    this.isOnSearch = false;
  }

  openModal(): void {
    this.ngxSmartModalService.getModal('filterSettings').open();
  }
}
