import {Directive, ElementRef, Input, OnInit} from '@angular/core';

import tippy from 'tippy.js';

@Directive({
  selector: '[appTippy]'
})
export class TippyDirective implements OnInit {
  @Input('appTippy') text = '';

  constructor(
    private elementRef: ElementRef
  ) {
  }

  ngOnInit(): void {
    tippy(this.elementRef.nativeElement, {
      content: this.text,
      theme: 'light'
    });
  }

}
